import React from 'react';

interface SelectProps extends React.SelectHTMLAttributes<HTMLSelectElement> {
  label?: string;
  options: { value: string; label: string }[];
  error?: string;
}

const labelStyle: React.CSSProperties = {
  display: 'block', fontSize: 'var(--font-size-sm)', fontWeight: 500,
  color: 'var(--color-neutral-700)', marginBottom: 'var(--spacing-1)',
};

export const Select: React.FC<SelectProps> = ({ label, options, error, style, id, ...props }) => (
  <div style={{ marginBottom: 'var(--spacing-4)' }}>
    {label && <label style={labelStyle}>{label}</label>}
    <select
      id={id}
      style={{
        width: '100%', padding: 'var(--spacing-2) var(--spacing-3)',
        fontSize: 'var(--font-size-base)', border: '1px solid var(--color-neutral-300)',
        borderRadius: 'var(--radius-md)', backgroundColor: '#fff',
        borderColor: error ? 'var(--color-error)' : undefined,
        ...style,
      }}
      {...props}
    >
      {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
    </select>
    {error && <p style={{ color: 'var(--color-error)', fontSize: 'var(--font-size-sm)', marginTop: 'var(--spacing-1)' }}>{error}</p>}
  </div>
);
